import React from 'react';

function Experience({ data }) {
  if (!data) return null;

  return (
    <section id="experience" className="py-8 md:py-12 bg-white">
      <div className="max-w-7xl mx-auto px-4">
        <p className="text-xs uppercase tracking-[0.35em] text-orange-500 font-semibold mb-4">
          Experience
        </p>
        <h2 className="text-4xl md:text-5xl font-black text-gray-900 mb-10">Selected Work</h2>

        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 border-t border-l border-gray-200">
          {data.map((exp, index) => (
            <article
              key={exp.id}
              className="min-h-[260px] border-r border-b border-gray-200 p-6 md:p-8 hover:bg-gray-50 transition-colors duration-200"
            >
              <p className="text-sm uppercase tracking-[0.35em] text-orange-500 mb-10">
                {String(index + 1).padStart(2, '0')}
              </p>

              <div className="flex items-start justify-between gap-4 mb-5">
                <div>
                  <h3 className="text-2xl font-black text-gray-900 mb-2 leading-tight">
                    {exp.position}
                  </h3>
                  <p className="text-sm uppercase tracking-[0.25em] text-gray-500">
                    {exp.company}
                  </p>
                </div>

                {exp.icon && (
                  <div className="flex-shrink-0 w-12 h-12 rounded-full bg-gray-900 text-white flex items-center justify-center text-xs font-bold tracking-widest">
                    {exp.icon}
                  </div>
                )}
              </div>

              <p className="text-sm text-gray-500 mb-4">{exp.period}</p>

              <div className="space-y-3 text-gray-600 leading-relaxed">
                {exp.description.map((item, idx) => (
                  <p key={idx} className="text-sm">
                    {item}
                  </p>
                ))}
              </div>
            </article>
          ))}
        </div>
      </div>
    </section>
  );
}

export default Experience;
